// Conway's Game of Life — GLSL TOP with Feedback
// Input 0: Feedback TOP (previous generation, R channel = alive/dead)
// Output: next generation

uniform float uThreshold; // e.g. 0.5

int getCell(vec2 uv, vec2 offset) {
    vec2 texel = 1.0 / uTD2DInfos[0].res.zw;
    vec4 s = texture(sTD2DInputs[0], uv + offset * texel);
    return (s.r > uThreshold) ? 1 : 0;
}

void main() {
    vec2 uv = vUV.st;
    int self = getCell(uv, vec2(0,0));

    // Count Moore neighborhood (8 neighbors)
    int neighbors = 
        getCell(uv, vec2(-1,-1)) + getCell(uv, vec2(0,-1)) + getCell(uv, vec2(1,-1)) +
        getCell(uv, vec2(-1, 0)) +                           getCell(uv, vec2(1, 0)) +
        getCell(uv, vec2(-1, 1)) + getCell(uv, vec2(0, 1)) + getCell(uv, vec2(1, 1));

    // Conway's rules: B3/S23
    int next = 0;
    if (self == 1 && (neighbors == 2 || neighbors == 3)) next = 1; // Survive
    if (self == 0 && neighbors == 3) next = 1;                     // Birth

    float v = float(next);
    fragColor = TDOutputSwizzle(vec4(v, v, v, 1.0));
}

