// Brian's Brain: states 0=dead, 0.5=dying, 1=alive
int state = (self > 0.75) ? 2 : (self > 0.25) ? 1 : 0; // 2=alive,1=dying,0=dead
int aliveNeighbors = 0; // count neighbors with state==2
// ... count as above but check > 0.75
int next = 0;
if (state == 2) next = 1; // alive -> dying
if (state == 1) next = 0; // dying -> dead
if (state == 0 && aliveNeighbors == 2) next = 2; // dead -> alive if exactly 2 alive neighbors

// Lenia: smooth kernel, continuous state
// Uses Gaussian kernel for neighborhood computation
// State is float 0..1, updated via growth function G(n) = exp(-((n-mu)^2)/(2*sigma^2))
float kernel_sample = 0.0;
// Sum weighted neighborhood with Gaussian kernel...
float growth = exp(-pow(kernel_sample - 0.15, 2.0) / (2.0 * 0.015 * 0.015));
float newState = clamp(self + 0.1 * (2.0 * growth - 1.0), 0.0, 1.0);
fragColor = TDOutputSwizzle(vec4(newState, newState, newState, 1.0));

