// Boids Update Shader — GLSL TOP ping-pong
// Texture layout: each pixel = one agent
// R=posx, G=posy, B=velx, A=vely (all normalized 0..1, remap to world space)
uniform float uDt;
uniform float uSepRadius;   // separation distance
uniform float uAliRadius;   // alignment radius
uniform float uCohRadius;   // cohesion radius
uniform float uSepWeight;
uniform float uAliWeight;
uniform float uCohWeight;
uniform float uMaxSpeed;    // e.g. 0.003

// World space from 0..1 texture
vec2 decode_pos(vec4 s) { return s.rg; }
vec2 decode_vel(vec4 s) { return s.ba * 2.0 - 1.0; } // -1..1

void main() {
    vec2 texel = 1.0 / uTD2DInfos[0].res.zw;
    vec2 uv = vUV.st;

    vec4 self = texture(sTD2DInputs[0], uv);
    vec2 pos = decode_pos(self);
    vec2 vel = decode_vel(self);

    vec2 sep = vec2(0.0), ali = vec2(0.0), coh = vec2(0.0);
    float sepN = 0.0, aliN = 0.0, cohN = 0.0;

    // Sample a subset of agents (cost: O(agents_sampled))
    // For full O(N^2): iterate all texels (expensive for large N)
    int W = int(uTD2DInfos[0].res.z);
    int H = int(uTD2DInfos[0].res.w);
    for (int i = 0; i < W; i += 4) { // stride=4 for performance
        for (int j = 0; j < H; j += 4) {
            vec2 nUV = (vec2(i, j) + 0.5) * texel;
            vec4 nb = texture(sTD2DInputs[0], nUV);
            vec2 npos = decode_pos(nb);
            vec2 nvel = decode_vel(nb);
            vec2 diff = pos - npos;
            float dist = length(diff);
            if (dist < 0.001) continue;
            if (dist < uSepRadius) { sep += normalize(diff) / dist; sepN++; }
            if (dist < uAliRadius) { ali += nvel; aliN++; }
            if (dist < uCohRadius) { coh += npos; cohN++; }
        }
    }

    vec2 steering = vec2(0.0);
    if (sepN > 0.0) steering += (sep / sepN) * uSepWeight;
    if (aliN > 0.0) steering += (ali / aliN - vel) * uAliWeight;
    if (cohN > 0.0) steering += ((coh / cohN) - pos) * uCohWeight;

    vel = vel + steering * uDt;
    float spd = length(vel);
    if (spd > uMaxSpeed) vel = vel / spd * uMaxSpeed;

    pos = fract(pos + vel); // wrap around

    fragColor = TDOutputSwizzle(vec4(pos, vel * 0.5 + 0.5));
}
